-- ============================================================
-- Full SQL for DOG_DB: tables + sample data
-- All table names are fully qualified (DOG_DB.SCHEMA.TABLE).
-- Paste into a Snowflake worksheet -> Ctrl+A -> Run All.
-- ============================================================

USE ROLE TRAINING_ROLE;
USE WAREHOUSE PANTHER_WH;
USE DATABASE DOG_DB;

-- ── 01_streaming_tables.sql ──
-- ============================================================
-- 01_streaming_tables.sql
-- Tables for real-time market data streamed from Polymarket
-- CLOB websocket and Data API REST endpoints.
-- Depends on: 00_bootstrap_polymarket.sql (creates RAW schema)
-- ============================================================

-- ----- trades captured from the market channel websocket -----
-- Each row is a single last_trade_price event from the WS.
-- wallet_address is NULL at insert time; enriched later by
-- joining against DATA_API_TRADES on (conditionId, timestamp,
-- size, price).
CREATE TABLE IF NOT EXISTS DOG_DB.DOG_SCHEMA.CLOB_TRADES_STREAM (
    stream_id               STRING          DEFAULT UUID_STRING(),
    asset_id                STRING          NOT NULL,
    market_condition_id     STRING          NOT NULL,
    side                    STRING,
    price                   NUMBER(18,6),
    size                    NUMBER(38,12),
    fee_rate_bps            NUMBER(18,2),
    ws_timestamp            TIMESTAMP_NTZ,
    wallet_address          STRING,
    enriched_at             TIMESTAMP_NTZ,
    raw_payload             VARIANT,
    streamed_at             TIMESTAMP_NTZ   DEFAULT CURRENT_TIMESTAMP()
);

-- ----- orderbook snapshots from the market channel websocket -----
-- Periodic book events give a full snapshot of bid/ask depth.
CREATE TABLE IF NOT EXISTS DOG_DB.DOG_SCHEMA.CLOB_BOOK_SNAPSHOTS (
    snapshot_id             STRING          DEFAULT UUID_STRING(),
    asset_id                STRING          NOT NULL,
    market_condition_id     STRING          NOT NULL,
    best_bid                NUMBER(18,6),
    best_ask                NUMBER(18,6),
    spread                  NUMBER(18,6),
    bid_depth               VARIANT,
    ask_depth               VARIANT,
    snapshot_ts             TIMESTAMP_NTZ,
    raw_payload             VARIANT,
    streamed_at             TIMESTAMP_NTZ   DEFAULT CURRENT_TIMESTAMP()
);

-- ----- trades pulled from the Data API REST endpoint -----
-- These include the proxyWallet (trader identity) that the
-- websocket does not provide.  Loaded by the order_flow_enrichment
-- Airflow DAG on a short schedule (every 15-30 min).
CREATE TABLE IF NOT EXISTS DOG_DB.DOG_SCHEMA.DATA_API_TRADES (
    proxy_wallet            STRING          NOT NULL,
    condition_id            STRING          NOT NULL,
    asset                   STRING,
    side                    STRING,
    outcome                 STRING,
    outcome_index           NUMBER(2,0),
    price                   NUMBER(18,6),
    size                    NUMBER(38,12),
    title                   STRING,
    slug                    STRING,
    event_slug              STRING,
    transaction_hash        STRING,
    trade_timestamp         TIMESTAMP_NTZ,
    raw_payload             VARIANT,
    loaded_at               TIMESTAMP_NTZ   DEFAULT CURRENT_TIMESTAMP(),
    UNIQUE (transaction_hash, proxy_wallet, condition_id)
);

-- ----- leaderboard user snapshots -----
-- Periodic snapshot of Polymarket leaderboard rankings.
-- Used to identify known whales and calibrate detection thresholds.
CREATE TABLE IF NOT EXISTS DOG_DB.DOG_SCHEMA.LEADERBOARD_USERS (
    proxy_wallet            STRING          NOT NULL,
    rank                    NUMBER(10,0),
    user_name               STRING,
    x_username              STRING,
    verified_badge          BOOLEAN,
    volume                  NUMBER(38,12),
    pnl                     NUMBER(38,12),
    profile_image           STRING,
    snapshot_date           DATE            DEFAULT CURRENT_DATE(),
    loaded_at               TIMESTAMP_NTZ   DEFAULT CURRENT_TIMESTAMP(),
    UNIQUE (proxy_wallet, snapshot_date)
);


-- ── 02_anomaly_tables.sql ──
-- ============================================================
-- 02_anomaly_tables.sql
-- Tables for anomaly detection results and daily aggregations.
-- Depends on: 00_bootstrap (RAW + CURATED schemas)
-- ============================================================

-- ----- raw anomaly events from the streaming detectors -----
CREATE TABLE IF NOT EXISTS DOG_DB.DOG_SCHEMA.DETECTED_ANOMALIES (
    anomaly_id              STRING          DEFAULT UUID_STRING(),
    detector_type           STRING          NOT NULL,
    market_condition_id     STRING          NOT NULL,
    asset_id                STRING,
    severity_score          NUMBER(18,6),
    details                 VARIANT,
    triggering_trades       VARIANT,
    detected_at             TIMESTAMP_NTZ   DEFAULT CURRENT_TIMESTAMP()
);

-- ----- daily per-market stats (built by order_flow_daily_agg DAG) -----
CREATE TABLE IF NOT EXISTS DOG_DB.DOG_TRANSFORM.MARKET_DAILY_STATS (
    market_condition_id     STRING          NOT NULL,
    stat_date               DATE            NOT NULL,
    trade_count             NUMBER(18,0),
    buy_count               NUMBER(18,0),
    sell_count              NUMBER(18,0),
    total_volume            NUMBER(38,12),
    total_usdc_volume       NUMBER(38,12),
    unique_wallets          NUMBER(18,0),
    avg_trade_size          NUMBER(38,12),
    median_trade_size       NUMBER(38,12),
    max_trade_size          NUMBER(38,12),
    vwap                    NUMBER(18,6),
    price_open              NUMBER(18,6),
    price_close             NUMBER(18,6),
    price_high              NUMBER(18,6),
    price_low               NUMBER(18,6),
    anomaly_count           NUMBER(18,0)    DEFAULT 0,
    computed_at             TIMESTAMP_NTZ   DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (market_condition_id, stat_date)
);

-- ----- daily per-wallet stats (built by order_flow_daily_agg DAG) -----
CREATE TABLE IF NOT EXISTS DOG_DB.DOG_TRANSFORM.WALLET_DAILY_STATS (
    proxy_wallet            STRING          NOT NULL,
    stat_date               DATE            NOT NULL,
    trade_count             NUMBER(18,0),
    distinct_markets        NUMBER(18,0),
    total_volume            NUMBER(38,12),
    total_usdc_volume       NUMBER(38,12),
    buy_volume              NUMBER(38,12),
    sell_volume             NUMBER(38,12),
    avg_trade_size          NUMBER(38,12),
    max_trade_size          NUMBER(38,12),
    anomaly_involvement     NUMBER(18,0)    DEFAULT 0,
    computed_at             TIMESTAMP_NTZ   DEFAULT CURRENT_TIMESTAMP(),
    PRIMARY KEY (proxy_wallet, stat_date)
);


-- ── 03_trader_profiles.sql ──
-- ============================================================
-- 03_trader_profiles.sql
-- Trader risk profiles and anomaly attribution.
-- Built nightly by the anomaly_attribution Airflow DAG.
-- Depends on: 01_streaming_tables, 02_anomaly_tables
-- ============================================================

-- ----- links a detected anomaly to the wallet(s) involved -----
CREATE TABLE IF NOT EXISTS DOG_DB.DOG_TRANSFORM.ANOMALY_ATTRIBUTION (
    attribution_id          STRING          DEFAULT UUID_STRING(),
    anomaly_id              STRING          NOT NULL,
    proxy_wallet            STRING          NOT NULL,
    market_condition_id     STRING          NOT NULL,
    trade_timestamp         TIMESTAMP_NTZ,
    trade_side              STRING,
    trade_size              NUMBER(38,12),
    trade_price             NUMBER(18,6),
    transaction_hash        STRING,
    attributed_at           TIMESTAMP_NTZ   DEFAULT CURRENT_TIMESTAMP(),
    UNIQUE (anomaly_id, proxy_wallet, transaction_hash)
);

-- ----- composite risk profile per wallet -----
CREATE TABLE IF NOT EXISTS DOG_DB.DOG_TRANSFORM.TRADER_RISK_PROFILES (
    proxy_wallet                    STRING          PRIMARY KEY,
    leaderboard_rank                NUMBER(10,0),
    total_trades                    NUMBER(18,0),
    total_volume                    NUMBER(38,12),
    distinct_markets                NUMBER(18,0),
    avg_trade_size                  NUMBER(38,12),
    max_single_trade                NUMBER(38,12),
    win_rate                        NUMBER(18,6),
    avg_seconds_before_resolution   NUMBER(18,2),
    anomaly_involvement_count       NUMBER(18,0)    DEFAULT 0,
    anomaly_involvement_rate        NUMBER(18,6)    DEFAULT 0,
    top_detector_type               STRING,
    risk_score                      NUMBER(18,6)    DEFAULT 0,
    first_seen                      TIMESTAMP_NTZ,
    last_seen                       TIMESTAMP_NTZ,
    updated_at                      TIMESTAMP_NTZ   DEFAULT CURRENT_TIMESTAMP()
);


